// Pass float values to the shader
shader.uniformf("floatUniform", 1.0f, 2.0f);

// Pass an array of float values to the shader
float[] myValues = {1.0f, 2.0f, 3.0f};
shader.uniformf("floatArrayUniform", myValues);

